#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m,v,a[N],c[N],f[1003][20];
bitset<14000> dp;

int lowbit(int x){
    return x&(-x);
}

int ask(int x){
    int sum=0;
    for(;x;x-=lowbit(x))
        sum+=c[x];
    return sum;
}

void add(int x,int k){
    for(;x<=n;x+=lowbit(x))
        c[x]+=k;
}

int main(){
    scanf("%d%d%d",&n,&m,&v);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=0;i<v;i++)
        f[i][0]=i*i*i%v;
    for(int j=1;j<20;j++)
        for(int i=0;i<v;i++)
            f[i][j]=f[f[i][j-1]][j-1];
    while(m--){
        int op,l,r;
        scanf("%d%d%d",&op,&l,&r);
        if(op==1){
            if(r-l+1>13){
                puts("Yuno");
                continue;
            }
            dp.reset();
            dp.set(0);
            bool flag=false;
            for(int i=l;i<=r;i++){
                int num=a[i],tmp=ask(i);
                for(int j=0;j<20;j++)
                    if(tmp&(1<<j))
                        num=f[num][j];
                bitset<14000> val=dp&(dp<<(num+1));
                if(val.count()){
                    flag=1;
                    break;
                }
                dp|=dp<<(num+1);
            }
            if(flag)
                puts("Yuno");
            else
                puts("Yuki");
        }else
            add(l,1),add(r+1,-1);
    }
    return 0;
}
